import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import Login from './pages/Login';
import Register from './pages/Register';
import InterviewerAvailability from './pages/interviewer/InterviewerAvailability';

function App() {
  return (
    <Router>
      <div className="min-h-screen bg-gray-50">
        <Navbar />

        <Routes>
          {/* Home Page - Modern Hero */}
          <Route path="/" element={<HomePage />} />

          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          <Route path="/interviewer/availability" element={<InterviewerAvailability />} />
        </Routes>
      </div>
    </Router>
  );
}

/* ==================== Modern Home Page ==================== */
const HomePage = () => {
  return (
    <div className="pt-16">
      {/* Hero Section */}
      <div className="relative overflow-hidden bg-gradient-to-br from-gray-900 via-blue-950 to-indigo-950 text-white">
        <div className="max-w-7xl mx-auto px-6 py-24 md:py-32 flex flex-col items-center text-center relative z-10">
          <div className="inline-flex items-center gap-2 bg-white/10 backdrop-blur-md px-4 py-2 rounded-full mb-6 border border-white/20">
            <span className="relative flex h-3 w-3">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-3 w-3 bg-green-500"></span>
            </span>
            <span className="text-sm font-medium">Now Open for Beta</span>
          </div>

          <h1 className="text-6xl md:text-7xl font-bold tracking-tighter leading-tight max-w-4xl">
            Master Interviews with <span className="bg-gradient-to-r from-blue-400 to-indigo-400 bg-clip-text text-transparent">Real Professionals</span>
          </h1>

          <p className="mt-6 text-xl md:text-2xl text-gray-300 max-w-2xl">
            Practice technical interviews with experienced engineers. 
            Get real-time feedback and boost your confidence.
          </p>

          <div className="flex flex-col sm:flex-row gap-4 mt-10">
            <a href="/register" 
               className="bg-white text-gray-900 font-semibold px-8 py-4 rounded-2xl text-lg hover:bg-gray-100 transition-all active:scale-95 shadow-xl shadow-black/30">
              Get Started for Free
            </a>

            <a href="#features" 
               className="border border-white/30 hover:bg-white/10 font-medium px-8 py-4 rounded-2xl text-lg transition-all">
              See How It Works
            </a>
          </div>

          <div className="mt-12 text-sm text-gray-400 flex items-center gap-8">
            <div>✓ No credit card required</div>
            <div>✓ 1000+ mock interviews conducted</div>
          </div>
        </div>

        {/* Background decoration */}
        <div className="absolute inset-0 bg-[radial-gradient(at_top_right,#4f46e510_0%,transparent_50%)]"></div>
      </div>

      {/* Features Section */}
      <div id="features" className="max-w-7xl mx-auto px-6 py-20">
        <div className="text-center mb-16">
          <h2 className="text-4xl font-bold text-gray-900">Why Choose MockInterviews?</h2>
          <p className="mt-4 text-gray-600 text-lg">Everything you need to ace your next interview</p>
        </div>

        <div className="grid md:grid-cols-3 gap-8">
          {features.map((feature, i) => (
            <div key={i} className="bg-white rounded-3xl p-8 shadow-sm hover:shadow-xl transition-all hover:-translate-y-1 border border-gray-100">
              <div className="w-12 h-12 bg-gradient-to-br from-blue-500 to-indigo-600 rounded-2xl flex items-center justify-center text-white mb-6">
                {feature.icon}
              </div>
              <h3 className="text-2xl font-semibold mb-3">{feature.title}</h3>
              <p className="text-gray-600 leading-relaxed">{feature.desc}</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

const features = [
  {
    icon: "🎯",
    title: "Real Interview Experience",
    desc: "Practice with senior engineers from top tech companies in realistic 45-60 minute sessions."
  },
  {
    icon: "📝",
    title: "Detailed Feedback",
    desc: "Get structured feedback on communication, problem-solving, system design, and behavioral skills."
  },
  {
    icon: "📅",
    title: "Flexible Scheduling",
    desc: "Book sessions that fit your timezone and schedule. Cancel or reschedule anytime."
  }
];

export default App;
